"BenchInvocation": {
  "additionalProperties": false,
  "description": "One analyst-defined stacks-bench invocation. The analyzer decides\nHOW the target gets measured — Phase 1.8 runs the baseline side of\neach invocation, Phase 3 mirrors it on the candidate side with\nidentical `(samples, warmup, repetitions, profiler)`, and the\npost-bench results-analyzer (Phase 3.5) pairs them by `id` to judge\n`measured_pct` against `expected_signal`.",
  "properties": {
    "expected_signal": {
      "$ref": "#/$defs/ExpectedSignal",
      "description": "Analyzer hypothesis for this invocation. Direction load-bearing."
    },
    "id": {
      "description": "Schema-validated path key. ASCII kebab-case, max 40 chars,\nregex [`INVOCATION_ID_PATTERN`]. Unique within a single\n`VerificationReplay.invocations` array (duplicates fail\nvalidation). Used in artifact paths\n(`verify/<target>/<id>/bench-run.json`,\n`optimize/<target>/<id>/bench-run.json`) and as the pairing key\nacross baseline ↔ candidate ↔ results-analysis.",
      "pattern": "^[a-z](?:[a-z0-9-]{0,38}[a-z0-9])?$",
      "type": "string"
    },
    "label": {
      "description": "Free-text human-facing label for prompts, the summary table, and\nthe PR body. Non-blank.",
      "type": "string"
    },
    "profiler": {
      "$ref": "#/$defs/ProfilerMode",
      "description": "Profiler shape. v1: `rich` only. Baseline + candidate for the\nsame `id` MUST match — that's the flag-symmetry contract."
    },
    "purpose": {
      "description": "One-line purpose: what this invocation tests and why. Surfaced in\nthe PR body and the results-analysis verdict.",
      "type": "string"
    },
    "repetitions": {
      "description": "Number of measured repetitions (`--repetitions` on stacks-bench).\n1..=200.",
      "format": "uint32",
      "maximum": 200,
      "minimum": 1,
      "type": "integer"
    },
    "samples": {
      "$ref": "#/$defs/BenchSamples",
      "description": "What to replay — tagged enum on `kind`."
    },
    "warmup": {
      "description": "Number of warmup repetitions discarded before measurement starts\n(`--warmup` on stacks-bench). 0..=200.",
      "format": "uint32",
      "maximum": 200,
      "minimum": 0,
      "type": "integer"
    }
  },
  "required": [
    "id",
    "label",
    "purpose",
    "samples",
    "warmup",
    "repetitions",
    "profiler",
    "expected_signal"
  ],
  "type": "object"
},
"BenchSamples": {
  "description": "Samples the analyzer wants a [`BenchInvocation`] to replay. Stacks-bench\ntreats txids and blocks as mutually-exclusive CLI inputs, so the\nvariants map 1:1 to `stacks-bench bench run` flag sets. Tagged enum\n(`kind` discriminator) for sharp validation errors + readable JSON.\n\nAll identifier values in `Txids` / `Blocks` are 0x-prefixed\n64-hex-char hashes ([`HEX_HASH_PATTERN`]). Heights and synthetic ids\nare NEVER acceptable; the analyzer picks identifiers from the\n`tx_hash` / `stacks_block_hash` columns, not from synthetic db ids\nthat are data-dir-local.",
  "oneOf": [
    {
      "additionalProperties": false,
      "description": "Transaction-replay invocation: `stacks-bench bench run --txid <hash>`\nfor each entry.",
      "properties": {
        "kind": {
          "const": "txids",
          "type": "string"
        },
        "txids": {
          "description": "1-16 representative transaction hashes.",
          "items": {
            "pattern": "^0x[0-9a-fA-F]{64}$",
            "type": "string"
          },
          "maxItems": 16,
          "minItems": 1,
          "type": "array"
        }
      },
      "required": [
        "kind",
        "txids"
      ],
      "type": "object"
    },
    {
      "additionalProperties": false,
      "description": "Block-replay invocation: `stacks-bench bench run --block <hash>`\nfor each entry.",
      "properties": {
        "blocks": {
          "description": "1-16 representative stacks index block hashes.",
          "items": {
            "pattern": "^0x[0-9a-fA-F]{64}$",
            "type": "string"
          },
          "maxItems": 16,
          "minItems": 1,
          "type": "array"
        },
        "kind": {
          "const": "blocks",
          "type": "string"
        }
      },
      "required": [
        "kind",
        "blocks"
      ],
      "type": "object"
    },
    {
      "additionalProperties": false,
      "description": "Full-range block-window invocation: `stacks-bench bench run\n--start-at <N> --count <M>`. Used when the analyzer wants a\ncanonical block range rather than a hand-picked sample.",
      "properties": {
        "count": {
          "description": "Block count to replay. 1..=50_000 — sanity ceiling.",
          "format": "uint64",
          "maximum": 50000,
          "minimum": 1,
          "type": "integer"
        },
        "kind": {
          "const": "block_range",
          "type": "string"
        },
        "start_at": {
          "description": "First block height to replay. >= 1.",
          "format": "uint64",
          "minimum": 1,
          "type": "integer"
        }
      },
      "required": [
        "kind",
        "start_at",
        "count"
      ],
      "type": "object"
    }
  ]
},
"BreakageClass": {
  "description": "Classification of a consensus-breaking change. Required when\n`consensus_breaking == true`.",
  "oneOf": [
    {
      "const": "clarity_cost_weight",
      "description": "Recalibrating a Clarity-VM cost weight (e.g. `costs.toml`).",
      "type": "string"
    },

        },
        {
          "const": "clarity_vm_behavior",
          "description": "Changing how the Clarity VM evaluates an opcode or function.",
          "type": "string"
        },
        {
          "const": "mining_flow",
          "description": "Block production logic (mempool ordering, tx admission, fee logic).\nExercised by stacks-bench.",
          "type": "string"
        },
        {
          "const": "block_validation",
          "description": "Block acceptance / header / signature checks. NOT exercised by\nstacks-bench — `poc_implementable` MUST be false.",
          "type": "string"
        },
        {
          "const": "marf_layout",
          "description": "MARF on-disk storage format change.",
          "type": "string"
        },
        {
          "const": "on_chain_format",
          "description": "Other consensus-relevant serialization changes.",
          "type": "string"
        }
      ]
    },
    "Bucket": {
      "description": "Work-bucket classification for a target. Determined by the nearest\n`Segment: ...` ancestor of the target span in the trace tree.",
      "oneOf": [
        {
          "const": "block_processing",
          "description": "Target lives under `Segment: Tx Execution` / `Transaction`.",
          "type": "string"
        },
        {
          "const": "block_commit",
          "description": "Target lives under one of the commit-bucket Segment anchors.",
          "type": "string"
        }
      ]
    },
    "EvidenceQuery": {
      "additionalProperties": false,
      "description": "Analyzer DB evidence that supports a target's mechanism hypothesis.\n\nThe analyzer writes query outputs under its analysis directory, records the\nbundled query it ran, the parameter values it used, the output path it\nwrote, and the specific observation it extracted. Merge carries this trail\nthrough to `optimization-targets.json`; the results-analyzer replays or\ncompares it against candidate runs.",
      "properties": {
        "key_observation": {
          "description": "Numeric, specific observation extracted from the query output.",
          "type": "string"
        },
        "output_path": {
          "description": "Analysis-output-relative path where the query result was written.",
          "type": "string"
        },
        "params": {
          "additionalProperties": {
            "type": "string"
          },
          "description": "Parameter values used by the analyzer when it ran the query.",
          "type": "object"
        },
        "purpose": {
          "description": "Why this query matters for the target.",
          "type": "string"
        },
        "sql_path": {
          "description": "Stable logical path of the bundled SQL file, always\n`queries/<name>.sql`.",
          "type": "string"
        },
        "supports_invocations": {
          "description": "Invocation ids this evidence supports.",
          "items": {
            "type": "string"
          },
          "minItems": 1,
          "type": "array"
        }
      },
      "required": [
        "purpose",
        "sql_path",
        "output_path",
        "key_observation",
        "supports_invocations"
      ],
      "type": "object"
    },
    "ExpectedSignal": {
      "additionalProperties": false,
      "description": "Per-invocation hypothesis: what the analyzer expects the measurement\nto show. Direction is the LOAD-BEARING piece (results-analyzer judges\nshape consistency first); magnitude is advisory (`estimate_pct`\noptional; tolerance optional). Splitting the qualitative claim from\nthe quantitative one lets the analyzer commit to direction while\nbeing honest about uncertain magnitudes (\"warm should improve;\ncould be 5% or 50% depending on working-set hit rate\").",
      "properties": {
        "axis": {
          "$ref": "#/$defs/SelectionLens",
          "description": "Selection lens the analyzer measured the candidate target against\n— same enum as `Candidate.selection_lens` and\n`LensDisposition.lens`."
        },
        "direction": {
          "$ref": "#/$defs/SignalDirection",
          "description": "Direction component. Load-bearing."
        },
        "estimate_pct": {
          "description": "Optional point estimate of the magnitude as a signed percent.\nConvention: positive = faster (consistent with\n`improvement_pct`'s sign). Skipped from output when absent.",
          "format": "double",
          "type": [
            "number",
            "null"
          ]
        },
        "tolerance_pct": {
          "description": "Optional non-negative tolerance band (also percent). When set\nalongside `estimate_pct`, the results-analyzer treats\n`[estimate_pct - tolerance_pct, estimate_pct + tolerance_pct]`\nas the expected range. With `direction == Neutral` and no\n`estimate_pct`, treats `[-tolerance_pct, +tolerance_pct]`.",
          "format": "double",
          "type": [
            "number",
            "null"
          ]
        }
      },
      "required": [
        "axis",
        "direction"
      ],
      "type": "object"
    },
    "Hotspot": {
      "additionalProperties": false,
      "description": "Hotspot record carried on every analyzer-emitted target and merged target.",
      "properties": {
        "calls": {
          "description": "Number of times the span was entered in the run.",
          "format": "int64",
          "type": "integer"
        },
        "location": {
          "description": "`file.rs:LINE` location string.",
          "type": "string"
        },
        "self_wall_us": {
          "description": "Exclusive wall time at the target span (microseconds).",
          "format": "int64",
          "type": "integer"
        },
        "span": {
          "description": "Span name as it appears in trace queries.",
          "type": "string"
        },
        "total_wall_us": {
          "description": "Inclusive wall time at the target span (self plus subtree, µs).",
          "format": "int64",
          "type": "integer"
        }
      },
      "required": [
        "span",
        "self_wall_us",
        "total_wall_us",
        "calls",
        "location"
      ],
      "type": "object"
    },
    "ImprovementVector": {
      "additionalProperties": false,
      "description": "Per-axis honest estimate of a fix's percent reduction on each value lens.\nAll three axes are required; use `0` for axes the fix doesn't move.",
      "properties": {
        "commit_time": {
          "description": "Percent reduction in commit-bucket wall time.",
          "format": "double",
          "type": "number"
        },
        "tenure_throughput": {
          "description": "Percent reduction in the binding Clarity-cost axis.",
          "format": "double",
          "type": "number"
        },
        "tx_latency": {
          "description": "Percent reduction in execution-bucket wall time.",
          "format": "double",
          "type": "number"
        }
      },
      "required": [
        "tx_latency",
        "tenure_throughput",
        "commit_time"
      ],
      "type": "object"
    },
    "LensDisposition": {
      "additionalProperties": false,
      "allOf": [
        {
          "if": {
            "properties": {
              "status": {
                "const": "not_actionable"
              }
            },
            "required": [
              "status"
            ]
          },
          "then": {
            "properties": {
              "reason": {
                "not": {
                  "type": "null"
                }
              }
            },
            "required": [
              "reason"
            ]
          }
        }
      ],
      "description": "Required lens disposition on accepted analyses.",
      "properties": {
        "lens": {
          "$ref": "#/$defs/SelectionLens",
          "description": "Lens being disposed of. Must equal the analysis's `selection_lens`."
        },
        "reason": {
          "description": "Required when `status == NotActionable`; optional but allowed when\n`status == Addressed`.",
          "type": [
            "string",
            "null"
          ]
        },
        "status": {
          "$ref": "#/$defs/LensDispositionStatus",
          "description": "Disposition status."
        }
      },
      "required": [
        "lens",
        "status"
